        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new PriceChainModelMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[PriceChainModelMessage](sbeTemplateId=");
            builder.Append(PriceChainModelMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(PriceChainModelMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != PriceChainModelMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(PriceChainModelMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != PriceChainModelMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(PriceChainModelMessage.BlockLength);
            builder.Append("):");

            builder.Append("IsFirm=");
            builder.Append(this.IsFirm);
            builder.Append('|');
            builder.Append("PossibleFirm=");
            builder.Append(this.PossibleFirm);
            builder.Append('|');
            builder.Append("PossibleCopyCat=");
            builder.Append(this.PossibleCopyCat);
            builder.Append('|');
            builder.Append("Uncertain=");
            builder.Append(this.Uncertain);
            builder.Append('|');
            builder.Append("QtyMismatch=");
            builder.Append(this.QtyMismatch);
            builder.Append('|');
            builder.Append("ScannerId=");
            builder.Append(this.ScannerId);
            builder.Append('|');
            builder.Append("BuyConditionCode=");
            builder.Append(this.BuyConditionCode);
            builder.Append('|');
            builder.Append("SellConditionCode=");
            builder.Append(this.SellConditionCode);
            builder.Append('|');
            builder.Append("AdjSide=");
            builder.Append(this.AdjSide);
            builder.Append('|');
            builder.Append("IbCobSide=");
            builder.Append(this.IbCobSide);
            builder.Append('|');
            builder.Append("LegsCount=");
            builder.Append(this.LegsCount);
            builder.Append('|');
            builder.Append("BuyQty=");
            builder.Append(this.BuyQty);
            builder.Append('|');
            builder.Append("SellQty=");
            builder.Append(this.SellQty);
            builder.Append('|');
            builder.Append("BuyBidSize=");
            builder.Append(this.BuyBidSize);
            builder.Append('|');
            builder.Append("BuyAskSize=");
            builder.Append(this.BuyAskSize);
